// script.js — vbforge-sandbox GitHub Pages
// Chart.js is initialized inline in index.html (generated by generate-site.sh)
// This file is reserved for any future interactive enhancements.

document.addEventListener('DOMContentLoaded', () => {
  // Animate stat numbers counting up
  document.querySelectorAll('.stat-number:not(.small)').forEach(el => {
    const target = parseInt(el.textContent, 10);
    if (isNaN(target) || target === 0) return;
    let current = 0;
    const step = Math.ceil(target / 20);
    const timer = setInterval(() => {
      current = Math.min(current + step, target);
      el.textContent = current;
      if (current >= target) clearInterval(timer);
    }, 40);
  });
});
